// Group orders by status within the last week
const aggregateResult = orders.aggregate([
  {
    $match: {
      date: {
        $gte: new Date(new Date().getTime() - 1000 * 3600 * 24 * 7),
        $lt: new Date(),
      },
    },
  },
  {
    $group: {
      _id: "$status",
      count: {
        $sum: 1,
      },
    },
  },
]);

for await (const doc of aggregateResult) {
  console.log(doc);
}
